// Typed accessor for the runtime SITE_CONFIG injected via public/site.config.js.
// Provides a safe fallback so the app never crashes if the script is missing.

import { logger } from './logger';

const FALLBACK: SiteConfig = {
  siteName: 'Alumni App',
  siteOwner: '',
  siteTagline: '',
  siteLogo: '',
  socials: {},
};

let cached: SiteConfig | null = null;

export function getSiteConfig(): SiteConfig {
  if (cached) return cached;
  if (typeof window === 'undefined' || !window.SITE_CONFIG) {
    logger.warn('siteConfig', 'window.SITE_CONFIG missing; using fallback');
    cached = FALLBACK;
    return cached;
  }
  cached = { ...FALLBACK, ...window.SITE_CONFIG };
  return cached;
}
